<!-- PostLive Component -->
defmodule MyAppWeb.PostLive do
  use Phoenix.LiveView

  alias MyApp.Blog

  def mount(%{"post_id" => post_id}, _session, socket) do
    post = Blog.get_post!(post_id)
    {:ok, assign(socket, post: post)}
  end

  def render(assigns) do
    ~L"""
